// Səbətdə meyvə olduğu müddətcə yeyirik
let fruits = ["alma", "banan", "portağal"];
while (fruits.length > 0) {
  let fruit = fruits.pop();
  console.log("Yediyim meyvə: " + fruit);
}
// nəticə:
// Yediyim meyvə: portağal
// Yediyim meyvə: banan
// Yediyim meyvə: alma

// Sayğac ilə nümunə
let counter = 5;
while (counter > 0) {
  console.log("Sayğac: " + counter);
  counter--; // Sayğacı azaldır
}
// nəticə:
// Sayğac: 5
// Sayğac: 4
// Sayğac: 3
// Sayğac: 2
// Sayğac: 1

// Blok scope ilə nümunə
while (true) {
  let message = "Dövr işləyir!";
  console.log(message);
  break; // Dövrü dayandırır
}
// console.log(message); // Xəta: message is not defined

// Müqayisə nümunəsi
let items = ["alma", "banan"];
while (items.length > 0) {
  console.log("while: " + items.pop());
}
// nəticə: while: banan, while: alma

// for ilə eyni iş
let newItems = ["alma", "banan"];
for (let i = 0; i < newItems.length; i++) {
  console.log("for: " + newItems[i]);
}
// nəticə: for: alma, for: banan

