// Eat fruits as long as the basket isn’t empty
let fruits = ["apple", "banana", "orange"];
while (fruits.length > 0) {
  let fruit = fruits.pop();
  console.log("Ate fruit: " + fruit);
}
// Output:
// Ate fruit: orange
// Ate fruit: banana
// Ate fruit: apple

// Example with a counter
let counter = 5;
while (counter > 0) {
  console.log("Counter: " + counter);
  counter--; // Decrease the counter
}
// Output:
// Counter: 5
// Counter: 4
// Counter: 3
// Counter: 2
// Counter: 1

// Block scope example
while (true) {
  let message = "Loop is running!";
  console.log(message);
  break; // Stops the loop
}
// console.log(message); // Error: message is not defined

// Comparison example
let items = ["apple", "banana"];
while (items.length > 0) {
  console.log("while: " + items.pop());
}
// Output: while: banana, while: apple

// Same task with for
let newItems = ["apple", "banana"];
for (let i = 0; i < newItems.length; i++) {
  console.log("for: " + newItems[i]);
}
// Output: for: apple, for: banana

