// Едим фрукты, пока корзина не пуста
let fruits = ["яблоко", "банан", "апельсин"];
while (fruits.length > 0) {
  let fruit = fruits.pop();
  console.log("Съел фрукт: " + fruit);
}
// Вывод:
// Съел фрукт: апельсин
// Съел фрукт: банан
// Съел фрукт: яблоко

// Пример со счётчиком
let counter = 5;
while (counter > 0) {
  console.log("Счётчик: " + counter);
  counter--; // Уменьшаем счётчик
}
// Вывод:
// Счётчик: 5
// Счётчик: 4
// Счётчик: 3
// Счётчик: 2
// Счётчик: 1

// Пример с блочной областью видимости
while (true) {
  let message = "Цикл работает!";
  console.log(message);
  break; // Останавливает цикл
}
// console.log(message); // Ошибка: message is not defined

// Пример сравнения
let items = ["яблоко", "банан"];
while (items.length > 0) {
  console.log("while: " + items.pop());
}
// Вывод: while: банан, while: яблоко

// То же самое с for
let newItems = ["яблоко", "банан"];
for (let i = 0; i < newItems.length; i++) {
  console.log("for: " + newItems[i]);
}
// Вывод: for: яблоко, for: банан

